"""Generate latent training data - problem -> code pairs"""
import pickle

p = 'dataset_cache/synthetic_code_reasoning.pkl'
texts = pickle.load(open(p, 'rb')) if __import__('os').path.exists(p) else []

samples = [
    ("Generate all valid parentheses for n pairs.", "def gen_parens(n):\n    res=[]\n    def dfs(o,c,path):\n        if o==c==n: res.append(''.join(path)); return\n        if o<n: dfs(o+1,c,path+['('])\n        if c<o: dfs(o,c+1,path+[')'])\n    dfs(0,0,[])\n    return res"),
    ("Unique paths in m x n grid, moving right/down.", "def unique_paths(m,n):\n    dp=[1]*n\n    for _ in range(1,m):\n        for j in range(1,n): dp[j]+=dp[j-1]\n    return dp[n-1]"),
    ("Unique paths II: grid with obstacles.", "def unique_paths_with_obs(grid):\n    if not grid or grid[0][0]==1: return 0\n    n=len(grid[0])\n    dp=[0]*n; dp[0]=1\n    for r in range(len(grid)):\n        for c in range(n):\n            if grid[r][c]==1: dp[c]=0\n            elif c>0: dp[c]+=dp[c-1]\n    return dp[n-1]"),
    ("Jump game: can you reach last index?", "def can_jump(nums):\n    furthest=0\n    for i,n in enumerate(nums):\n        if i>furthest: return False\n        furthest=max(furthest,i+n)\n    return True"),
    ("Jump game II: minimum jumps to reach end.", "def jump(nums):\n    jumps=cur_end=furthest=0\n    for i in range(len(nums)-1):\n        furthest=max(furthest,i+nums[i])\n        if i==cur_end:\n            jumps+=1; cur_end=furthest\n    return jumps"),
    ("Gas station: can you complete circuit?", "def can_complete(gas,cost):\n    if sum(gas)<sum(cost): return -1\n    tank=start=0\n    for i in range(len(gas)):\n        tank+=gas[i]-cost[i]\n        if tank<0: start=i+1; tank=0\n    return start"),
    ("Number of provinces (connected components).", "def find_circle_num(isConnected):\n    n=len(isConnected)\n    visited=[False]*n\n    def dfs(i):\n        visited[i]=True\n        for j in range(n):\n            if isConnected[i][j] and not visited[j]: dfs(j)\n    c=0\n    for i in range(n):\n        if not visited[i]: c+=1; dfs(i)\n    return c"),
    ("Rotting oranges: minutes until all rot.", "from collections import deque\ndef oranges_rotting(grid):\n    m,n=len(grid),len(grid[0])\n    q=deque()\n    fresh=0\n    for i in range(m):\n        for j in range(n):\n            if grid[i][j]==2: q.append((i,j,0))\n            elif grid[i][j]==1: fresh+=1\n    if fresh==0: return 0\n    while q:\n        i,j,mins=q.popleft()\n        for di,dj in ((1,0),(-1,0),(0,1),(0,-1)):\n            ni,nj=i+di,j+dj\n            if 0<=ni<m and 0<=nj<n and grid[ni][nj]==1:\n                grid[ni][nj]=2; fresh-=1\n                if fresh==0: return mins+1\n                q.append((ni,nj,mins+1))\n    return -1"),
    ("01 Matrix: distance to nearest 0.", "from collections import deque\ndef update_matrix(mat):\n    m,n=len(mat),len(mat[0])\n    q=deque()\n    for i in range(m):\n        for j in range(n):\n            if mat[i][j]==0: q.append((i,j))\n            else: mat[i][j]=-1\n    while q:\n        i,j=q.popleft()\n        for di,dj in ((1,0),(-1,0),(0,1),(0,-1)):\n            ni,nj=i+di,j+dj\n            if 0<=ni<m and 0<=nj<n and mat[ni][nj]==-1:\n                mat[ni][nj]=mat[i][j]+1\n                q.append((ni,nj))\n    return mat"),
    ("Flood fill: replace connected same-color cells.", "def flood_fill(image,sr,sc,color):\n    orig=image[sr][sc]\n    if orig==color: return image\n    def dfs(i,j):\n        if i<0 or i>=len(image) or j<0 or j>=len(image[0]) or image[i][j]!=orig: return\n        image[i][j]=color\n        dfs(i+1,j); dfs(i-1,j); dfs(i,j+1); dfs(i,j-1)\n    dfs(sr,sc)\n    return image"),
    ("Sort colors (Dutch flag): sort 0,1,2 in-place.", "def sort_colors(nums):\n    l,m,r=0,0,len(nums)-1\n    while m<=r:\n        if nums[m]==0:\n            nums[l],nums[m]=nums[m],nums[l]; l+=1; m+=1\n        elif nums[m]==1: m+=1\n        else:\n            nums[m],nums[r]=nums[r],nums[m]; r-=1\n    return nums"),
    ("Find disappeared numbers in array (1..n).", "def find_disappeared(nums):\n    for n in nums:\n        idx=abs(n)-1\n        nums[idx]=-abs(nums[idx])\n    return [i+1 for i,n in enumerate(nums) if n>0]"),
    ("House robber: max sum no adjacent.", "def rob(nums):\n    prev=cur=0\n    for n in nums:\n        prev,cur=cur,max(cur,prev+n)\n    return cur"),
    ("House robber II: houses in circle.", "def rob_ii(nums):\n    if len(nums)==1: return nums[0]\n    def rob_linear(arr):\n        prev=cur=0\n        for n in arr: prev,cur=cur,max(cur,prev+n)\n        return cur\n    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))"),
    ("Decode ways: count decodings (A=1..Z=26).", "def num_decodings(s):\n    if not s or s[0]=='0': return 0\n    p2,p1=1,1\n    for i in range(1,len(s)):\n        cur=0\n        if s[i]!='0': cur+=p1\n        if 10<=int(s[i-1:i+1])<=26: cur+=p2\n        p2,p1=p1,cur\n    return p1"),
    ("Perfect squares: min count summing to n.", "def num_squares(n):\n    dp=[float('inf')]*(n+1)\n    dp[0]=0\n    for i in range(1,n+1):\n        j=1\n        while j*j<=i:\n            dp[i]=min(dp[i],dp[i-j*j]+1)\n            j+=1\n    return dp[n]"),
    ("Buy/sell stock: one transaction max profit.", "def max_profit(prices):\n    buy=float('inf'); profit=0\n    for p in prices:\n        if p<buy: buy=p\n        elif p-buy>profit: profit=p-buy\n    return profit"),
    ("Buy/sell stock II: unlimited transactions.", "def max_profit_ii(prices):\n    profit=0\n    for i in range(1,len(prices)):\n        if prices[i]>prices[i-1]: profit+=prices[i]-prices[i-1]\n    return profit"),
    ("Buy/sell stock III: at most 2 transactions.", "def max_profit_iii(prices):\n    b1=b2=float('inf')\n    p1=p2=0\n    for p in prices:\n        b1=min(b1,p); p1=max(p1,p-b1)\n        b2=min(b2,p-p1); p2=max(p2,p-b2)\n    return p2"),
    ("Longest common subsequence of two strings.", "def lcs(text1,text2):\n    m,n=len(text1),len(text2)\n    dp=[[0]*(n+1) for _ in range(m+1)]\n    for i in range(1,m+1):\n        for j in range(1,n+1):\n            if text1[i-1]==text2[j-1]: dp[i][j]=1+dp[i-1][j-1]\n            else: dp[i][j]=max(dp[i-1][j],dp[i][j-1])\n    return dp[m][n]"),
    ("Combination sum: combos summing to target (unlimited use).", "def combination_sum(candidates,target):\n    res=[]\n    def dfs(start,path,remaining):\n        if remaining==0: res.append(path[:]); return\n        for i in range(start,len(candidates)):\n            if candidates[i]<=remaining:\n                dfs(i,path+[candidates[i]],remaining-candidates[i])\n    dfs(0,[],target)\n    return res"),
    ("Combination sum II: each used once, no duplicates.", "def combination_sum2(candidates,target):\n    candidates.sort(); res=[]\n    def dfs(start,path,remaining):\n        if remaining==0: res.append(path[:]); return\n        for i in range(start,len(candidates)):\n            if i>start and candidates[i]==candidates[i-1]: continue\n            if candidates[i]>remaining: break\n            dfs(i+1,path+[candidates[i]],remaining-candidates[i])\n    dfs(0,[],target)\n    return res"),
    ("Subsets II: all subsets with duplicates.", "def subsets_with_dup(nums):\n    nums.sort(); res=[]\n    def dfs(i,path):\n        res.append(path[:])\n        for j in range(i,len(nums)):\n            if j>i and nums[j]==nums[j-1]: continue\n            dfs(j+1,path+[nums[j]])\n    dfs(0,[])\n    return res"),
    ("Word search: does word exist in 2D board?", "def exist(board,word):\n    m,n=len(board),len(board[0])\n    def dfs(i,j,k):\n        if k==len(word): return True\n        if i<0 or i>=m or j<0 or j>=n or board[i][j]!=word[k]: return False\n        tmp,board[i][j]=board[i][j],'#'\n        found=dfs(i+1,j,k+1) or dfs(i-1,j,k+1) or dfs(i,j+1,k+1) or dfs(i,j-1,k+1)\n        board[i][j]=tmp\n        return found\n    for i in range(m):\n        for j in range(n):\n            if dfs(i,j,0): return True\n    return False"),
    ("Evaluate Reverse Polish Notation.", "def eval_rpn(tokens):\n    stack=[]\n    for t in tokens:\n        if t in '+-*/':\n            b,a=stack.pop(),stack.pop()\n            if t=='+': stack.append(a+b)\n            elif t=='-': stack.append(a-b)\n            elif t=='*': stack.append(a*b)\n            else: stack.append(int(a/b))\n        else: stack.append(int(t))\n    return stack[0]"),
    ("Implement Trie: insert, search, startsWith.", "class Trie:\n    def __init__(self): self.children={}; self.end=False\n    def insert(self,word):\n        n=self\n        for c in word: n=n.children.setdefault(c,Trie())\n        n.end=True\n    def search(self,word):\n        n=self\n        for c in word:\n            if c not in n.children: return False\n            n=n.children[c]\n        return n.end\n    def startsWith(self,prefix):\n        n=self\n        for c in prefix:\n            if c not in n.children: return False\n            n=n.children[c]\n        return True"),
    ("Queue using two stacks.", "class MyQueue:\n    def __init__(self): self.s1=[]; self.s2=[]\n    def push(self,x): self.s1.append(x)\n    def pop(self):\n        self._transfer()\n        return self.s2.pop()\n    def peek(self):\n        self._transfer()\n        return self.s2[-1]\n    def empty(self): return not self.s1 and not self.s2\n    def _transfer(self):\n        if not self.s2:\n            while self.s1: self.s2.append(self.s1.pop())"),
    ("Min Stack: push, pop, top, getMin O(1).", "class MinStack:\n    def __init__(self): self.s=[]\n    def push(self,x):\n        if not self.s: self.s.append((x,x))\n        else: self.s.append((x,min(x,self.s[-1][1])))\n    def pop(self): self.s.pop()\n    def top(self): return self.s[-1][0]\n    def getMin(self): return self.s[-1][1]"),
    ("Valid Sudoku: check board configuration.", "def is_valid_sudoku(board):\n    rows=[set() for _ in range(9)]\n    cols=[set() for _ in range(9)]\n    boxes=[set() for _ in range(9)]\n    for i in range(9):\n        for j in range(9):\n            v=board[i][j]\n            if v=='.': continue\n            b=i//3*3+j//3\n            if v in rows[i] or v in cols[j] or v in boxes[b]: return False\n            rows[i].add(v); cols[j].add(v); boxes[b].add(v)\n    return True"),
    ("First unique character in string.", "def first_uniq_char(s):\n    cnt={}\n    for c in s: cnt[c]=cnt.get(c,0)+1\n    for i,c in enumerate(s):\n        if cnt[c]==1: return i\n    return -1"),
    ("Isomorphic strings: characters can be replaced.", "def is_isomorphic(s,t):\n    return len(set(zip(s,t)))==len(set(s))==len(set(t))"),
    ("Merge overlapping intervals.", "def merge_intervals(intervals):\n    intervals.sort(key=lambda x:x[0])\n    res=[intervals[0]]\n    for s,e in intervals[1:]:\n        if s<=res[-1][1]: res[-1][1]=max(res[-1][1],e)\n        else: res.append([s,e])\n    return res"),
    ("Insert interval into sorted non-overlapping intervals.", "def insert_interval(intervals,new):\n    res=[]; i=0; ns,ne=new\n    while i<len(intervals) and intervals[i][1]<ns:\n        res.append(intervals[i]); i+=1\n    while i<len(intervals) and intervals[i][0]<=ne:\n        ns=min(ns,intervals[i][0]); ne=max(ne,intervals[i][1]); i+=1\n    res.append([ns,ne])\n    while i<len(intervals): res.append(intervals[i]); i+=1\n    return res"),
    ("Meeting rooms II: minimum rooms needed.", "import heapq\ndef min_rooms(intervals):\n    intervals.sort(key=lambda x:x[0])\n    heap=[]\n    rooms=0\n    for s,e in intervals:\n        while heap and heap[0]<=s: heapq.heappop(heap)\n        heapq.heappush(heap,e)\n        rooms=max(rooms,len(heap))\n    return rooms"),
    ("Add two numbers represented by linked lists.", "def add_two(l1,l2):\n    dummy=tail=ListNode()\n    carry=0\n    while l1 or l2 or carry:\n        v1=l1.val if l1 else 0\n        v2=l2.val if l2 else 0\n        total=v1+v2+carry\n        tail.next=ListNode(total%10)\n        carry=total//10\n        tail=tail.next\n        if l1: l1=l1.next\n        if l2: l2=l2.next\n    return dummy.next"),
    ("Palindrome linked list.", "def is_palindrome(head):\n    slow=fast=head\n    while fast and fast.next:\n        slow=slow.next; fast=fast.next.next\n    prev=None\n    while slow:\n        nxt=slow.next; slow.next=prev; prev=slow; slow=nxt\n    while prev:\n        if prev.val!=head.val: return False\n        prev=prev.next; head=head.next\n    return True"),
    ("Linked list cycle II: return cycle start node.", "def detect_cycle(head):\n    slow=fast=head\n    while fast and fast.next:\n        slow=slow.next; fast=fast.next.next\n        if slow==fast:\n            slow=head\n            while slow!=fast:\n                slow=slow.next; fast=fast.next\n            return slow\n    return None"),
    ("Same tree: are two binary trees identical?", "def is_same(p,q):\n    if not p and not q: return True\n    if not p or not q: return False\n    return p.val==q.val and is_same(p.left,q.left) and is_same(p.right,q.right)"),
    ("Symmetric tree: mirror of itself?", "def is_symmetric(root):\n    def same(l,r):\n        if not l and not r: return True\n        if not l or not r or l.val!=r.val: return False\n        return same(l.left,r.right) and same(l.right,r.left)\n    return same(root.left,root.right) if root else True"),
    ("Convert sorted array to height-balanced BST.", "def sorted_array_to_bst(nums):\n    def build(l,r):\n        if l>r: return None\n        m=(l+r)//2\n        n=TreeNode(nums[m])\n        n.left=build(l,m-1); n.right=build(m+1,r)\n        return n\n    return build(0,len(nums)-1)"),
    ("Balanced binary tree: height diff <=1?", "def is_balanced(root):\n    def dfs(n):\n        if not n: return 0\n        l=dfs(n.left); r=dfs(n.right)\n        if l==-1 or r==-1 or abs(l-r)>1: return -1\n        return 1+max(l,r)\n    return dfs(root)!=-1"),
    ("Lowest common ancestor in BST.", "def lca_bst(root,p,q):\n    while root:\n        if p.val<root.val and q.val<root.val: root=root.left\n        elif p.val>root.val and q.val>root.val: root=root.right\n        else: return root"),
    ("Lowest common ancestor in binary tree.", "def lca(root,p,q):\n    if not root or root==p or root==q: return root\n    l=lca(root.left,p,q); r=lca(root.right,p,q)\n    if l and r: return root\n    return l or r"),
    ("Binary tree maximum path sum.", "def max_path_sum(root):\n    best=float('-inf')\n    def dfs(n):\n        nonlocal best\n        if not n: return 0\n        l=max(dfs(n.left),0); r=max(dfs(n.right),0)\n        best=max(best,l+r+n.val)\n        return n.val+max(l,r)\n    dfs(root)\n    return best"),
    ("Validate BST: in-order iterative.", "def is_valid_bst(root):\n    stack=[]; prev=float('-inf')\n    while stack or root:\n        while root:\n            stack.append(root); root=root.left\n        root=stack.pop()\n        if root.val<=prev: return False\n        prev=root.val; root=root.right\n    return True"),
    ("Binary tree inorder traversal (iterative).", "def inorder(root):\n    res=[]; stack=[]\n    while stack or root:\n        while root:\n            stack.append(root); root=root.left\n        root=stack.pop()\n        res.append(root.val); root=root.right\n    return res"),
    ("Binary tree preorder traversal (iterative).", "def preorder(root):\n    if not root: return []\n    res=[]; stack=[root]\n    while stack:\n        n=stack.pop()\n        res.append(n.val)\n        if n.right: stack.append(n.right)\n        if n.left: stack.append(n.left)\n    return res"),
    ("Binary tree postorder traversal (iterative).", "def postorder(root):\n    if not root: return []\n    res=[]; stack=[(root,False)]\n    while stack:\n        n,visited=stack.pop()\n        if visited: res.append(n.val)\n        else:\n            stack.append((n,True))\n            if n.right: stack.append((n.right,False))\n            if n.left: stack.append((n.left,False))\n    return res"),
    ("Climbing stairs: ways to climb n stairs (1 or 2 steps).", "def climb_stairs(n):\n    a=b=1\n    for _ in range(n):\n        a,b=b,a+b\n    return a"),
    ("Min cost climbing stairs.", "def min_cost_climbing(cost):\n    a=b=0\n    for c in reversed(cost):\n        a,b=c+min(a,b),a\n    return min(a,b)"),
    ("Delete node in linked list (given only the node).", "def delete_node(node):\n    node.val=node.next.val\n    node.next=node.next.next"),
    ("Find the duplicate number in array (n+1 numbers 1..n).", "def find_duplicate(nums):\n    slow=fast=nums[0]\n    while True:\n        slow=nums[slow]; fast=nums[nums[fast]]\n        if slow==fast: break\n    slow=nums[0]\n    while slow!=fast:\n        slow=nums[slow]; fast=nums[fast]\n    return slow"),
    ("Contains duplicate: any value appears twice?", "def contains_duplicate(nums):\n    return len(set(nums))!=len(nums)"),
    ("Contains duplicate II: within k distance.", "def contains_nearby(nums,k):\n    seen={}\n    for i,n in enumerate(nums):\n        if n in seen and i-seen[n]<=k: return True\n        seen[n]=i\n    return False"),
    ("Power of three: is n a power of 3?", "def is_power_of_three(n):\n    if n<=0: return False\n    while n%3==0: n//=3\n    return n==1"),
    ("Fizz Buzz: classic.", "def fizzbuzz(n):\n    res=[]\n    for i in range(1,n+1):\n        if i%15==0: res.append('FizzBuzz')\n        elif i%3==0: res.append('Fizz')\n        elif i%5==0: res.append('Buzz')\n        else: res.append(str(i))\n    return res"),
    ("Count primes less than n.", "def count_primes(n):\n    if n<3: return 0\n    is_p=[True]*n\n    is_p[0]=is_p[1]=False\n    for i in range(2,int(n**0.5)+1):\n        if is_p[i]:\n            is_p[i*i:n:i]=[False]*(((n-1-i*i)//i)+1)\n    return sum(is_p)"),
    ("Roman to integer.", "def roman_to_int(s):\n    vals={'I':1,'V':5,'X':10,'L':50,'C':100,'D':500,'M':1000}\n    res=0\n    for i,c in enumerate(s):\n        if i+1<len(s) and vals[c]<vals[s[i+1]]: res-=vals[c]\n        else: res+=vals[c]\n    return res"),
    ("Integer to roman.", "def int_to_roman(n):\n    vals=[(1000,'M'),(900,'CM'),(500,'D'),(400,'CD'),(100,'C'),(90,'XC'),(50,'L'),(40,'XL'),(10,'X'),(9,'IX'),(5,'V'),(4,'IV'),(1,'I')]\n    res=[]\n    for v,sym in vals:\n        while n>=v:\n            res.append(sym); n-=v\n    return ''.join(res)"),
    ("Longest common prefix among strings.", "def longest_common_prefix(strs):\n    if not strs: return ''\n    for i in range(len(strs[0])):\n        for s in strs[1:]:\n            if i>=len(s) or s[i]!=strs[0][i]: return strs[0][:i]\n    return strs[0]"),
    ("Length of last word in string.", "def length_of_last_word(s):\n    return len(s.strip().split()[-1]) if s.strip() else 0"),
    ("Add binary strings.", "def add_binary(a,b):\n    return bin(int(a,2)+int(b,2))[2:]"),
    ("Sqrt(x): integer square root without built-in.", "def my_sqrt(x):\n    if x<2: return x\n    l,r=1,x//2\n    while l<=r:\n        m=(l+r)//2\n        if m*m==x: return m\n        elif m*m<x: l=m+1\n        else: r=m-1\n    return r"),
    ("Excel sheet column title from number.", "def convert_to_title(n):\n    res=[]\n    while n>0:\n        n-=1\n        res.append(chr(ord('A')+n%26))\n        n//=26\n    return ''.join(reversed(res))"),
    ("Two sum II: sorted array, return indices (1-indexed).", "def two_sum_sorted(nums,target):\n    l,r=0,len(nums)-1\n    while l<r:\n        s=nums[l]+nums[r]\n        if s==target: return [l+1,r+1]\n        elif s<target: l+=1\n        else: r-=1\n    return []"),
    ("Majority element II: appears > n/3 times.", "def majority_element(nums):\n    c1=c2=0; cand1=cand2=None\n    for n in nums:\n        if n==cand1: c1+=1\n        elif n==cand2: c2+=1\n        elif c1==0: cand1=n; c1=1\n        elif c2==0: cand2=n; c2=1\n        else: c1-=1; c2-=1\n    res=[]\n    for c in (cand1,cand2):\n        if nums.count(c)>len(nums)//3: res.append(c)\n    return res"),
    ("Reverse words in a string.", "def reverse_words(s):\n    return ' '.join(reversed(s.split()))"),
    ("Compare version numbers.", "def compare_version(v1,v2):\n    p1=[int(x) for x in v1.split('.')]\n    p2=[int(x) for x in v2.split('.')]\n    for i in range(max(len(p1),len(p2))):\n        n1=p1[i] if i<len(p1) else 0\n        n2=p2[i] if i<len(p2) else 0\n        if n1>n2: return 1\n        elif n1<n2: return -1\n    return 0"),
    ("Fraction to recurring decimal.", "def fraction_to_decimal(num,den):\n    if num==0: return '0'\n    res='-' if (num<0)^(den<0) else ''\n    num,den=abs(num),abs(den)\n    res+=str(num//den)\n    r=num%den\n    if r==0: return res\n    res+='.'\n    seen={}\n    while r:\n        if r in seen:\n            res=res[:seen[r]]+'('+res[seen[r]:]+')'\n            break\n        seen[r]=len(res)\n        r*=10\n        res+=str(r//den)\n        r%=den\n    return res"),
    ("Factorial trailing zeros count.", "def trailing_zeros(n):\n    c=0\n    while n>=5: n//=5; c+=n\n    return c"),
    ("Happy number detection.", "def is_happy(n):\n    seen=set()\n    while n!=1 and n not in seen:\n        seen.add(n)\n        n=sum(int(d)**2 for d in str(n))\n    return n==1"),
    ("Remove element in-place, return new length.", "def remove_element(nums,val):\n    i=0\n    for n in nums:\n        if n!=val: nums[i]=n; i+=1\n    return i"),
    ("Implement strStr(): index of first occurrence.", "def str_str(haystack,needle):\n    if not needle: return 0\n    for i in range(len(haystack)-len(needle)+1):\n        if haystack[i:i+len(needle)]==needle: return i\n    return -1"),
    ("Search insert position in sorted array.", "def search_insert(nums,target):\n    l,r=0,len(nums)\n    while l<r:\n        m=(l+r)//2\n        if nums[m]>=target: r=m\n        else: l=m+1\n    return l"),
    ("Maximum subarray (Kadane) return subarray too.", "def max_subarray_with_indices(nums):\n    cur=best=nums[0]\n    l=r=tmp=0\n    for i,n in enumerate(nums[1:],1):\n        if n>cur+n:\n            cur=n; tmp=i\n        else: cur+=n\n        if cur>best:\n            best=cur; l=tmp; r=i\n    return best,nums[l:r+1]"),
    ("Pascals triangle: first n rows.", "def generate(n):\n    res=[[1]]\n    for _ in range(1,n):\n        row=[1]\n        for j in range(1,len(res[-1])):\n            row.append(res[-1][j-1]+res[-1][j])\n        row.append(1)\n        res.append(row)\n    return res"),
    ("Pascals triangle II: get row k (0-indexed).", "def get_row(k):\n    row=[1]\n    for _ in range(k):\n        row=[1]+[row[i]+row[i+1] for i in range(len(row)-1)]+[1]\n    return row"),
    ("Valid palindrome: alphanumeric only, ignore case.", "def is_palindrome_str(s):\n    clean=[c.lower() for c in s if c.isalnum()]\n    return clean==clean[::-1]"),
    ("Word break II: return all possible sentences.", "def word_break_ii(s,word_dict):\n    words=set(word_dict); memo={}\n    def dfs(i):\n        if i in memo: return memo[i]\n        res=[]\n        if i==len(s): res.append(''); return res\n        for j in range(i+1,len(s)+1):\n            if s[i:j] in words:\n                for sub in dfs(j):\n                    res.append(s[i:j]+(' '+sub if sub else ''))\n        memo[i]=res\n        return res\n    return dfs(0)"),
    ("Interleaving string: is s3 interleave of s1 and s2?", "def is_interleave(s1,s2,s3):\n    if len(s1)+len(s2)!=len(s3): return False\n    dp=[False]*(len(s2)+1)\n    for i in range(len(s1)+1):\n        for j in range(len(s2)+1):\n            if i==0 and j==0: dp[j]=True\n            elif i==0: dp[j]=dp[j-1] and s2[j-1]==s3[i+j-1]\n            elif j==0: dp[j]=dp[j] and s1[i-1]==s3[i+j-1]\n            else: dp[j]=(dp[j] and s1[i-1]==s3[i+j-1]) or (dp[j-1] and s2[j-1]==s3[i+j-1])\n    return dp[len(s2)]"),
    ("Distinct subsequences: count ways s2 appears in s1.", "def num_distinct(s1,s2):\n    m,n=len(s1),len(s2)\n    dp=[[0]*(n+1) for _ in range(m+1)]\n    for i in range(m+1): dp[i][0]=1\n    for i in range(1,m+1):\n        for j in range(1,n+1):\n            dp[i][j]=dp[i-1][j]\n            if s1[i-1]==s2[j-1]: dp[i][j]+=dp[i-1][j-1]\n    return dp[m][n]"),
    ("Word ladder II: all shortest transformation sequences.", "from collections import deque,defaultdict\ndef find_ladders(begin,end,words):\n    ws=set(words); res=[]\n    if end not in ws: return res\n    q=deque([[begin]])\n    found=False; visited=set()\n    while q and not found:\n        local_vis=set()\n        for _ in range(len(q)):\n            path=q.popleft(); w=path[-1]\n            if w==end: res.append(path); found=True\n            for i in range(len(w)):\n                for c in 'abcdefghijklmnopqrstuvwxyz':\n                    nw=w[:i]+c+w[i+1:]\n                    if nw in ws and nw not in visited:\n                        local_vis.add(nw)\n                        q.append(path+[nw])\n        visited|=local_vis\n    return res"),
    ("Median of two sorted arrays O(log(min(m,n))).", "def find_median_sorted_arrays(a,b):\n    if len(a)>len(b): a,b=b,a\n    m,n=len(a),len(b)\n    l,r=0,m\n    while l<=r:\n        i=(l+r)//2; j=(m+n+1)//2-i\n        al=a[i-1] if i>0 else float('-inf')\n        ar=a[i] if i<m else float('inf')\n        bl=b[j-1] if j>0 else float('-inf')\n        br=b[j] if j<n else float('inf')\n        if al<=br and bl<=ar:\n            if (m+n)%2==0: return (max(al,bl)+min(ar,br))/2\n            else: return max(al,bl)\n        elif al>br: r=i-1\n        else: l=i+1"),
]

for prob, code in samples:
    t = f"<|user|>\n{prob}\n<|assistant|>\n{code}\n<|end|>"
    texts.append(t)

import pickle
p_out = 'dataset_cache/synthetic_code_reasoning.pkl'
pickle.dump(texts, open(p_out, 'wb'))
print(f'Total: {len(texts)} samples, {sum(len(t.split()) for t in texts):,} tokens')
